import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"A-MEM: Agentic Memory for LLM Agents","description":"","frontmatter":{"title":"A-MEM: Agentic Memory for LLM Agents","arxiv_id":2502.1211,"authors":"Wujiang Xu, Zujie Liang, Kai Mei, et al.","published":"2025-02-17T00:00:00.000Z","source":"https://arxiv.org/abs/2502.12110","source_tier":"P"},"headers":[],"relativePath":"research/papers/2025-02-17-amem-agentic-memory-llm-agents-2502-12110.md","filePath":"research/papers/2025-02-17-amem-agentic-memory-llm-agents-2502-12110.md","lastUpdated":1779901665000}'),n={name:"research/papers/2025-02-17-amem-agentic-memory-llm-agents-2502-12110.md"};function i(l,t,s,d,h,m){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="a-mem-agentic-memory-for-llm-agents" tabindex="-1">A-MEM: Agentic Memory for LLM Agents <a class="header-anchor" href="#a-mem-agentic-memory-for-llm-agents" aria-label="Permalink to &quot;A-MEM: Agentic Memory for LLM Agents&quot;">​</a></h1><p><strong>ArXiv</strong>: 2502.12110 | <strong>Date</strong>: 2025-02-17 (修訂 2025-10-08) | <strong>Venue</strong>: NeurIPS 2025 | <strong>Authors</strong>: Wujiang Xu, Zujie Liang, Kai Mei, et al. | <strong>Category</strong>: cs.CL</p><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>解決 LLM agent 記憶系統的關鍵差距：「當前記憶系統能夠基本存取和檢索，但缺乏複雜的記憶組織。」採用 Zettelkasten 筆記方法論（強調互聯知識）結合 agent 驅動決策，實現動態記憶組織。</p><h2 id="核心方法" tabindex="-1">核心方法 <a class="header-anchor" href="#核心方法" aria-label="Permalink to &quot;核心方法&quot;">​</a></h2><h3 id="動態記憶組織" tabindex="-1">動態記憶組織 <a class="header-anchor" href="#動態記憶組織" aria-label="Permalink to &quot;動態記憶組織&quot;">​</a></h3><p>不同於靜態結構，新資訊進入時：</p><ol><li>生成包含多結構屬性的完整筆記（上下文描述、關鍵詞、標籤）</li><li>分析歷史記憶識別相關連接</li><li>在相關概念間建立有意義的連結</li></ol><h3 id="記憶演化機制" tabindex="-1">記憶演化機制 <a class="header-anchor" href="#記憶演化機制" aria-label="Permalink to &quot;記憶演化機制&quot;">​</a></h3><p>新記憶整合時可觸發<strong>現有記憶表示的更新</strong>，使系統對知識庫的理解持續精化。</p><h2 id="主要結果" tabindex="-1">主要結果 <a class="header-anchor" href="#主要結果" aria-label="Permalink to &quot;主要結果&quot;">​</a></h2><p>在使用 6 個基礎模型的評估中，超越現有 SOTA 基準。</p><p>（代碼倉庫：github.com/WujiangXu/A-mem）</p><h2 id="zettelkasten-方法論" tabindex="-1">Zettelkasten 方法論 <a class="header-anchor" href="#zettelkasten-方法論" aria-label="Permalink to &quot;Zettelkasten 方法論&quot;">​</a></h2><p>德語「卡片盒」，一種知識管理系統，核心原則：</p><ul><li>原子化筆記（一個概念一個筆記）</li><li>互聯引用（概念間顯式連結）</li><li>湧現結構（從連結中湧現的高層理解）</li></ul><p>將此原則應用於 agent 記憶，使記憶不再是孤立向量點，而是互聯的知識網絡。</p><h2 id="與其他記憶系統的對比" tabindex="-1">與其他記憶系統的對比 <a class="header-anchor" href="#與其他記憶系統的對比" aria-label="Permalink to &quot;與其他記憶系統的對比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>系統</th><th>組織方式</th><th>演化機制</th></tr></thead><tbody><tr><td>純向量 RAG</td><td>語義相似性</td><td>無</td></tr><tr><td>HippoRAG</td><td>KG + PageRank</td><td>部分</td></tr><tr><td><strong>A-MEM</strong></td><td>Zettelkasten 互聯</td><td><strong>動態更新現有記憶</strong></td></tr></tbody></table><h2 id="分類" tabindex="-1">分類 <a class="header-anchor" href="#分類" aria-label="Permalink to &quot;分類&quot;">​</a></h2><p><strong>Memory Architecture</strong> — NeurIPS 2025 論文，Zettelkasten 式互聯記憶組織是向量 RAG 之後的重要進化方向，動態記憶演化機制值得在生產環境記憶系統中考慮。</p>',21)])])}const u=e(n,[["render",i]]);export{c as __pageData,u as default};
